q=7
for a in range(q):
    for b in range(q):
        for c in range(q):
            for d in range(q):
                det=(a*d-b*c)%q
                if det==0: 
                    continue
                if (a+d)%q!=0:
                    continue
                # condition (ii): no eigenvalue in F_q
                has_ev=False
                for lam in range(q):
                    if ((a-lam)*(d-lam)-b*c)%q==0:
                        has_ev=True
                        break
                if not has_ev:
                    count+=1
print(count)  # 126

