from math import cos, pi
m,n=3,4
vals=[]
for j in range(m):
    lam=2-2*cos(2*pi*j/m)
    for k in range(n):
        mu=2-2*cos(2*pi*k/n)
        vals.append(round(lam+mu,12))
prod=1
for v in vals:
    if abs(v)>1e-12:
        prod*=v
